import type { ChangeEvent, FC } from "react"
import { useState } from "react"
import { vi } from "vitest"
import { page, render } from "#test/browser"
import { useControllableEventState, useControllableState } from "./"

describe("useControllableEventState", () => {
  test("reads ev.target.value for non-boolean inputs", async () => {
    const onChange = vi.fn()

    const Component: FC = () => {
      const [value, setValue] = useControllableEventState<
        string,
        HTMLInputElement
      >({
        defaultValue: "",
        onChange,
      })

      return (
        <input
          type="text"
          aria-label="Test input"
          value={value}
          onChange={setValue}
        />
      )
    }

    const { user } = await render(<Component />)

    await user.fill(page.getByRole("textbox"), "hello")

    expect(onChange).toHaveBeenCalledTimes(1)
    const ev = onChange.mock.calls[0]![0] as ChangeEvent<HTMLInputElement>
    expect(ev.target.value).toBe("hello")
  })

  test("updates defaultValue in uncontrolled mode", async () => {
    const Component: FC = () => {
      const [value, setValue] = useControllableEventState<
        string,
        HTMLInputElement
      >({
        defaultValue: "initial",
      })

      return (
        <input
          type="text"
          aria-label="Test input"
          value={value}
          onChange={setValue}
        />
      )
    }

    const { user } = await render(<Component />)

    await user.fill(page.getByRole("textbox"), "updated")

    await expect.element(page.getByRole("textbox")).toHaveValue("updated")
  })
})

describe("useControllableState", () => {
  test("works in uncontrolled mode with defaultValue", async () => {
    const Component: FC = () => {
      const [value, setValue] = useControllableState<string>({
        defaultValue: "initial",
      })

      return <button onClick={() => setValue("updated")}>{value}</button>
    }

    const { user } = await render(<Component />)

    await expect.element(page.getByRole("button")).toHaveTextContent("initial")

    await user.click(page.getByRole("button"))

    await expect.element(page.getByRole("button")).toHaveTextContent("updated")
  })

  test("works in controlled mode", async () => {
    const onChange = vi.fn()

    const Component: FC = () => {
      const [value, setValue] = useState("controlled")
      const [state, setState] = useControllableState<string>({
        value,
        onChange: (v) => {
          onChange(v)
          setValue(v)
        },
      })

      return <button onClick={() => setState("new")}>{state}</button>
    }

    const { user } = await render(<Component />)

    await expect
      .element(page.getByRole("button"))
      .toHaveTextContent("controlled")

    await user.click(page.getByRole("button"))

    expect(onChange).toHaveBeenCalledWith("new")
    await expect.element(page.getByRole("button")).toHaveTextContent("new")
  })
})

"use client"

import type {
  ChangeEvent,
  ChangeEventHandler,
  Dispatch,
  SetStateAction,
} from "react"
import { useState } from "react"
import {
  isBoolean,
  isNull,
  isUndefined,
  runIfFn,
  useCallbackRef,
} from "@yamada-ui/react"

interface UseControllableStateMethods<Y> {
  onChange?: (value: Y) => void
  onUpdate?: (prev: Y, next: Y) => boolean
}

export interface UseControllableStateProps<
  Y,
> extends UseControllableStateMethods<Y> {
  defaultValue?: (() => Y) | Y
  value?: Y
}

export function useControllableState<Y>(
  props: UseControllableStateMethods<Y> & {
    value: Y
    defaultValue?: (() => Y) | Y
  },
): [Y, Dispatch<SetStateAction<Y>>]

export function useControllableState<Y>(
  props: UseControllableStateMethods<Y> & {
    defaultValue: (() => Y) | Y
    value?: Y
  },
): [Y, Dispatch<SetStateAction<Y>>]

export function useControllableState<Y>(
  props: UseControllableStateProps<Y>,
): [Y, Dispatch<SetStateAction<Y>>]

export function useControllableState<Y>({
  defaultValue: defaultValueProp,
  value,
  onChange: onChangeProp,
  onUpdate: onUpdateProp = (prev, next) => prev !== next,
}: UseControllableStateProps<Y>) {
  const onChange = useCallbackRef(onChangeProp)
  const onUpdate = useCallbackRef(onUpdateProp)
  const [defaultValue, setDefaultValue] = useState(defaultValueProp)
  const controlled = !isUndefined(value)
  const currentValue = (controlled ? value : defaultValue) as Y

  const setValue = useCallbackRef(
    (next: SetStateAction<Y>) => {
      const nextValue = runIfFn(next, currentValue)

      if (!onUpdate(currentValue, nextValue)) return

      if (!controlled || isUndefined(nextValue) || isNull(nextValue))
        setDefaultValue(nextValue)

      onChange(nextValue)
    },
    [controlled, currentValue, onChange, onUpdate],
  )

  return [currentValue, setValue]
}

function isHTMLInputElement(el: HTMLElement): el is HTMLInputElement {
  return el instanceof HTMLInputElement
}

interface UseControllableEventStateMethods<
  Y extends HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement,
> {
  onChange?: ChangeEventHandler<Y>
}

export interface UseControllableEventStateProps<
  Y extends boolean | number | string,
  M extends HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement,
> extends UseControllableEventStateMethods<M> {
  defaultValue?: (() => Y) | Y
  value?: Y
}

export function useControllableEventState<
  Y extends boolean | number | string,
  M extends HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement,
>(
  props: UseControllableEventStateMethods<M> & {
    value: Y
    defaultValue?: (() => Y) | Y
  },
): [Y, ChangeEventHandler<M>]

export function useControllableEventState<
  Y extends boolean | number | string,
  M extends HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement,
>(
  props: UseControllableEventStateMethods<M> & {
    defaultValue: (() => Y) | Y
    value?: Y
  },
): [Y, ChangeEventHandler<M>]

export function useControllableEventState<
  Y extends boolean | number | string,
  M extends HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement,
>(props: UseControllableEventStateProps<Y, M>): [Y, ChangeEventHandler<M>]

export function useControllableEventState<
  Y extends boolean | number | string,
  M extends HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement,
>({
  defaultValue: defaultValueProp,
  value,
  onChange: onChangeProp,
}: UseControllableEventStateProps<Y, M>) {
  const onChange = useCallbackRef(onChangeProp)
  const [defaultValue, setDefaultValue] = useState(defaultValueProp)
  const controlled = !isUndefined(value)
  const currentValue = (controlled ? value : defaultValue) as Y
  const boolean = isBoolean(currentValue)

  const setValue = useCallbackRef(
    (ev: ChangeEvent<M>) => {
      const value =
        boolean && isHTMLInputElement(ev.target)
          ? (ev.target.checked as Y)
          : (ev.target.value as Y)

      if (!controlled || isUndefined(value) || isNull(value))
        setDefaultValue(value)

      onChange(ev)
    },
    [controlled, currentValue, onChange],
  )

  return [currentValue, setValue]
}
